import axios from 'axios';

export const API_BASE_URL = process.env.REACT_APP_API_BASE_URL || 'http://localhost:5012';

const apiClient = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

const DEPARTMENT_NAME_BY_CODE = {
  CCS: 'College of Computer Studies',
  CAS: 'College of Arts and Sciences',
  CBA: 'College of Business & Accountancy',
  EDUC: 'College of Teacher Education',
  COEA: 'College of Engineering, Architecture & Aviation',
  CIHM: 'College of International Hospitality Management',
  CME: 'College of Maritime Education',
  LJD: 'Law/Juris Doctor',
  SOA: 'School of Aviation',
};

const normalizeDepartmentRecord = (department) => {
  if (!department || typeof department !== 'object') return department;

  const code = (department.code || department.departmentCode || '')
    .toString()
    .trim()
    .toUpperCase();

  const normalizedName = DEPARTMENT_NAME_BY_CODE[code];

  if (!normalizedName) {
    return department;
  }

  return {
    ...department,
    name: normalizedName,
    departmentName: normalizedName,
  };
};

const extractArray = (data) => {
  if (Array.isArray(data)) return data;
  if (data?.items && Array.isArray(data.items)) return data.items;
  if (data?.data && Array.isArray(data.data)) return data.data;
  return [];
};

const normalizeDepartmentArray = (data) => extractArray(data).map((dept) => normalizeDepartmentRecord(dept));

// Request interceptor to add auth token
apiClient.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Response interceptor to handle errors
apiClient.interceptors.response.use(
  (response) => response,
  (error) => {
    const requestUrl = error.config?.url || '';
    const isAuthHandshakeRequest = requestUrl.includes('/api/auth/login');

    if (error.response?.status === 401 && !isAuthHandshakeRequest) {
      localStorage.removeItem('token');
      localStorage.removeItem('user');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

